import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface UsageBreakdown {
  category: string;
  percentage: number;
}

interface BatteryStatus {
  chargeLevel: number;
  status: string;
  timeRemaining: string;
  usageBreakdown: UsageBreakdown[];
}

export default function Widget() {
  const batteryStatus = response.data as BatteryStatus;
  const { chargeLevel, status, timeRemaining, usageBreakdown } = batteryStatus;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 420, bgcolor: '#1C1C1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="#FFC107">
              Battery Status
            </Typography>
            <Typography variant="h3" fontWeight={500} sx={{ color: '#FF5722', my: 0.5 }}>
              {chargeLevel}%
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {status} - {timeRemaining} remaining
            </Typography>
          </Box>

          <PieChart
            height={140}
            series={[
              {
                data: usageBreakdown.map(item => item.percentage),
                color: ['#FF5722', '#FFC107', '#FF9800', '#FFCC80'],
              },
            ]}
            pieSeries={[
              {
                name: 'Usage Breakdown',
                data: usageBreakdown.map(item => ({ name: item.category, value: item.percentage })),
              },
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiPieElement-root': {
                strokeWidth: 1,
                stroke: '#1C1C1E',
              },
              '& .MuiArcLabel-root': {
                fontSize: 11,
                fill: '#FFF',
              }
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
